/**
 *  Build Mappings Document Table
 *
 *  Script to generate an HTML table documenting CQL indexes and Search Scopes
 *  in terms of property names, marc mappings, and RC labels. Leverages the
 *  generic JSON document generated by the sibling build-mappings-document.js
 *  script.
 *
 *  Usage:
 *    node scripts/build-mappings-document-table.js --outfile OUT.html [--report (searchScopes|cqlIndexes)]
 *
 *  Other supported options:
 *   --includemarc:   Include "MARC Fields included in search" column
 *   --includenotes:  Add Notes column
 *   --infile STRING: Specify a rc-mappings file to use. Defaults to generating it on the fly.
 *
 *  For example, to build a CQL Indexes table with Marc mappings:
 *    node scripts/build-mappings-document-table.js --includemarc --report cqlIndexes --outfile cql-indexes-table.html
 */

const { parseArgs: _parseArgs } = require('node:util')
const fs = require('fs')
const { buildMappingsDocument } = require('./build-mappings-document')

const formatMarcQuery = (marc) => {
  const out = []
  if (marc.marc) {
    out.push(marc.marc)
    if (marc.subfields) out.push(marc.subfields.join(''))
    if (marc.excludedSubfields) out.push('-' + marc.excludedSubfields.join(''))
  }
  return '<span class="marc-path">' + out.join(' ') + '</span>'
}

const labelForProperty = (property) => {
  let label = property.label
  if (!label) {
    label = property.name
      .split(/(?=[A-Z])/)
      .map((s) => s[0].toUpperCase() + s.substring(1))
      .join(' ')
  }
  return label
}

const parallelName = (field) => {
  const capitalizedName = field.charAt(0).toUpperCase() + field.slice(1)
  return `parallel${capitalizedName}`
}

/**
 *  Builds array of entries for named report. Each entry is an array of values
 * */
const buildEntries = (scopesOrIndexes, propertyDefinitions) => {
  return scopesOrIndexes
    .filter((scopeOrIndex) => scopeOrIndex.properties)
    .map((scopeOrIndex) => {
      // Create a function to determine if a named property appears to have a
      // parallel equivalent in this scope/index:
      const hasParallel = (prop) => {
        return scopeOrIndex.parallelProperties?.includes(parallelName(prop))
      }

      // Build marc fields content:
      const marcFields = scopeOrIndex.properties
        .map((propertyName) => {
          const property = propertyDefinitions.find((p) => p.name === propertyName)
          if (!property) {
            console.warn(`Warning: Couldn't find property ${propertyName}`)
          }
          let lines = []

          // If no marc mappings known, show mapping notes instead:
          if (!property?.marc) {
            if (property?.notes) lines.push(property.notes)
            else lines.push(`[${propertyName} mapping unknown]`)
          } else {
            lines = property.marc.map(formatMarcQuery)

            // If we also match this property's parallel, note that:
            if (hasParallel(propertyName)) {
              lines.push(`<em>Also includes 880 equivalent${property.marc.length !== 1 ? 's' : ''}</em>`)
            }
          }

          const marcQueries = '<ul>' +
            lines.map((s) => `\n      <li>${s}</li>`).join('') +
            '</ul>'
          return labelForProperty(property) + ': ' + marcQueries
        })
        .sort()
        .join('\n')

      return {
        name: scopeOrIndex.name,
        advSearchEquivalent: scopeOrIndex.advSearchEquivalent,
        notes: scopeOrIndex.notes,
        marcFields
      }
    })
}

const styles = `
<style type="text/css">
table { border-collapse: collapse; }

td { vertical-align: top; border: solid gray 1px; padding: 0.5em; }

thead { font-weight: bold; }

.marc-path { font-family: monospace; }
</style>
`

const parseArgs = () => {
  return _parseArgs({
    args: process.args,
    options: {
      includemarc: {
        type: 'boolean',
        default: false
      },
      outfile: {
        type: 'string'
      },
      infile: {
        type: 'string'
      },
      report: {
        default: 'searchScopes',
        type: 'string'
      },
      includenotes: {
        type: 'boolean',
        default: false
      }
    }
  }).values
}

/**
 *  Main script function. Generates a search documentation table based on args.
 */
const run = async () => {
  const args = parseArgs()

  const headers = ['Query Index', 'Advanced Search Equivalent (if applicable)']
  if (args.includemarc) {
    headers.splice(2, 0, 'MARC Fields included in search')
  }
  if (args.includenotes) {
    headers.push('Notes')
  }

  let data
  if (args.infile) {
    data = JSON.parse(fs.readFileSync(args.infile, 'utf-8'))
  } else {
    data = await buildMappingsDocument()
  }

  // Get an array of either search scopes or cql indexes based on --report:
  const scopesOrIndexes = data[args.report]
  const outDoc = [
    styles,
    '<table>',
    '<thead>',
    '  <tr>' + headers.map((l) => `\n    <td>${l}</td>`).join('') + '\n</tr>',
    '</thead>',
    '<tbody>',
    ...buildEntries(scopesOrIndexes, data.properties)
      .map((entry) => {
        // Convert key-value object into array:
        const row = [entry.name, entry.advSearchEquivalent]

        if (args.includenotes) {
          row.push(entry.notes)
        }

        if (args.includemarc) {
          row.push(entry.marcFields)
        }

        return row
      })
      .map((cells) => {
        return '  <tr>' + cells.map((cell) => `\n    <td>${cell || ''}</td>`).join('') + '\n  </tr>'
      }),
    '</tbody>',
    '</table>'
  ].join('\n')

  if (args.outfile) {
    console.log(`Writing html table to ${args.outfile}`)
    fs.writeFileSync(args.outfile, outDoc, 'utf-8')
  } else {
    console.log(outDoc)
  }
}

run()
